import React, { useMemo, useState } from "react";
import {
  Crosshair,
  HorizontalGridLines,
  LineMarkSeries,
  LineMarkSeriesPoint,
  LineSeries,
  VerticalGridLines,
  XAxis,
  XYPlot,
  YAxis,
} from "react-vis";
import { GpsRecord } from "../flightData";
import "../../node_modules/react-vis/dist/style.css";
import { AutoSizer } from "react-virtualized";

type AltitudeChartProps = {
  gpsRecordArray: GpsRecord[];
  onNearestX?: ({ x }: { x: number }) => void;
};

export const AltitudeChart = ({
  gpsRecordArray,
  onNearestX,
}: AltitudeChartProps) => {
  const [points, setPoints] = useState<LineMarkSeriesPoint[]>([]);
  const data = useMemo(
    () => gpsRecordArray.map(({ altitude }, x) => ({ x, y: altitude })),
    [],
  );
  return (
    <>
      <AutoSizer>
        {({ height, width }) => (
          <XYPlot
            // onMouseLeave={() => this.setState({ value: false })}
            width={width}
            height={height}
            onMouseLeave={() => setPoints([])}
          >
            <VerticalGridLines />
            <HorizontalGridLines />
            <XAxis />
            <YAxis />
            <LineSeries
              data={data}
              onNearestX={(v) => {
                setPoints([v]);
                onNearestX && onNearestX({ x: v.x });
              }}
            />
            <Crosshair
              values={points}
              titleFormat={(v) => ({ title: "point", value: v[0].x })}
              itemsFormat={([v]) => ([{ title: "altitude", value: v.y }])}
            />
          </XYPlot>
        )}
      </AutoSizer>
    </>
  );
};
